return ['x-generator'=>'GlotPress/4.0.1','translation-revision-date'=>'2024-01-05 09:26:49+0000','plural-forms'=>'nplurals=2; plural=n != 1;','project-id-version'=>'Plugins - Redirection - Stable (latest release)','language'=>'es_CO','messages'=>['Something went wrong obtaining this information. It may work in the future.'=>'Algo ha ido mal al obtener esta información. Podría funcionar en el futuro.','If your browser is behaving differently then you should clear your browser cache.'=>'Si tu navegador se está comportando de manera diferente, entonces deberías vaciar la caché de tu navegador.','If this is not expected then this {{support}}support page{{/support}} may help.'=>'Si no es lo esperado, entonces esta {{support}}página de soporte{{/support}} puede ayudar.','Unable to check that URL. It may not be valid or accessible.'=>'No ha sido posible comprobar esa URL. Podría no ser válida o no estar accesible.','Matches your redirect'=>'Coincide con tu redirección','Something is wrong with the server. This is not a problem with Redirection and you will need to resolve the error yourself.'=>'Algo ha ido mal con el servidor. No es un problema de Redirection y tendrás que resolver el error por ti mismo.','An unknown errorm'=>'Un error desconocido','REST API 404'=>'404 de la API REST','Your server configuration is blocking access to the REST API.'=>'La configuración de tu servidor está bloqueando el acceso a la API REST.','Can you access your {{api}}REST API{{/api}} without it redirecting?.'=>'¿Puedes acceder a tu {{api}}API REST{{/api}} sin redirigir?','You will will need to fix this on your site. Redirection is not causing the error.'=>'Tienes que corregir esto en tu sitio. Redirection no está provocando el error.','Note: this is in beta and will only migrate posts. Certain permalinks will not work. If yours does not work then you will need to wait until it is out of beta.'=>'Nota: Esto está en beta y solo migrará las entradas. Ciertos enlaces permanentes no funcionarán. Si los tuyos no funcionan, tendrás que esperar a que deje de ser beta.','Nothing to display.'=>'Nada que mostrar.','Sometimes your browser can cache a URL, making it hard to know if it\'s working as expected. Use this service from {{link}}redirect.li{{/link}} to get accurate results.'=>'A veces tu navegador puede almacenar una URL en la caché, complicando saber si está funcionando como se espera. Usa este servicio de {{link}}redirect.li{{/link}} para obtener resultados precisos.','View full redirect.li results.'=>'Mira los resultados completos de redirect.li.','Page was loaded.'=>'Se ha cargado la página.','Redirected by an unknown agent. {{support}}What does this mean?{{/support}}.'=>'Redirigida por un agente desconocido. {{support}}¿Qué significa esto?{{/support}}','Redirected by %1s. {{support}}What does this mean?{{/support}}.'=>'Redirigida por %1s. {{support}}¿Qué significa esto?{{/support}}','Redirected by Redirection.'=>'Redirigida por Redirection.','An error page was returned. This is unlikely to be a problem with Redirection. {{support}}What does this mean?{{/support}}.'=>'Se ha devuelto una página de error. Es poco probable que se trate de un problema con Reditection. {{support}}¿Qué significa esto?{{/support}}.','The caret {{code}}^{{/code}} should be at the start. For example: {{code}}%(example)s{{/code}}'=>'El símbolo {{code}}^{{/code}} debería estar al principio. Por ejemplo: {{code}}%(example)s{{/code}}','Your REST API appears to be cached and this will cause problems. Please exclude your REST API from your caching system.'=>'Tu API REST parece estar cacheada y esto provocará problemas. Por favor, excluye tu API REST de tu sistema de caché.','Your REST API is showing a deprecated PHP error. Please fix this error.'=>'Tu API REST está mostrando un error PHP obsoleto. Por favor, corrige este error.','Add Permalink'=>'Añadir enlace permanente','No migrated permalinks'=>'Ningún enlace permanente migrado','Permalinks'=>'Enlaces permanentes','Enter old permalinks structures to automatically migrate them to your current one.'=>'Introduce viejas estructuras de enlaces permanentes para migrarlas automáticamente a las actuales.','Permalink Migration'=>'Migración de enlaces permanentes','(beta) Enable caching of redirects via WordPress object cache. Can improve performance. Requires an object cache.'=>'(beta) Activa la caché de redirecciones a través de la caché de objetos de WordPress. Puede mejorar el rendimiento. Requiere caché de objetos.','HTTP Cache Header'=>'Cabecera HTTP caché','Decide how Redirection updates itself, if needed.'=>'Decide cómo se actualiza Redirection, si fuese necesario.','Data Upgrade'=>'Actualización de datos','Advanced'=>'Avanzado','Automatically upgrade on admin pages'=>'Actualización automática en las páginas de administración','Upgrade manually when prompted'=>'Actualización manual cuando haya un aviso','%1d of %1d selected. {{all}}Clear All.{{/all}}'=>'%1d de %1d seleccionadas. {{all}}Vaciar todo.{{/all}}','%1d of %1d selected. {{all}}Select All.{{/all}}'=>'%1d de %1d seleccionadas. {{all}}Seleccionar todo.{{/all}}','Search exact URL'=>'Buscar la URL exacta','Version %s installed! Please read the {{url}}release notes{{/url}} for details.'=>'¡Versión %s instalada! Por favor, lee las {{url}}notas de la versión{{/}} para más detalles.','Are you sure want to delete all %d matching items?'=>'¿Estás seguro de querer borrar todos los elementos que coincidan con %d?','Please add migrated permalinks to the Site page under the "Permalink Migration" section.'=>'Por favor, añade los enlaces permanentes migrados a la página del sitio, en la sección de «Migración de enlaces permanentes».','Exact match in any order'=>'Coincidencia exacta en cualquier orden','Too many regular expressions may impact site performance'=>'Demasiadas expresiones regulares pueden impactar en el rendimiento del sitio','Regular Expressions'=>'Expresiones regulares','Your admin pages are being cached. Clear this cache and try again. There may be multiple caches involved.'=>'Tus páginas de administración están en caché. Vacía esta caché e inténtalo de nuevo. Puede haber varias cachés.','This is usually fixed by doing one of the following:'=>'Esto normalmente se corrige haciendo algo de lo siguiente:','You are using an old or cached session'=>'Estás usando una sesión antigua o en caché','Please review your data and try again.'=>'Por favor, revisa tus datos e inténtalo de nuevo.','Bad data'=>'Datos malos','WordPress returned an unexpected message. This could be a PHP error from another plugin, or data inserted by your theme.'=>'WordPress devolvió un mensaje inesperado. Esto podría deberse a un error de PHP de otro plugin, o a datos insertados por tu tema.','Your WordPress REST API has been disabled. You will need to enable it to continue.'=>'Tu API REST de WordPress se ha desactivado. Tendrías que activarla para continuar.','An unknown error occurred.'=>'Ocurrió un error desconocido.','Your REST API is being redirected. Please remove the redirection for the API.'=>'Tu API REST está siendo redirigida. Por favor, elimina la redirección de la API.','A security plugin or firewall is blocking access. You will need to whitelist the REST API.'=>'Un plugin de seguridad o un cortafuegos está bloqueando el acceso. Tendrías que poner en lista blanca la API REST.','Check your {{link}}Site Health{{/link}} and fix any issues.'=>'Comprueba la {{link}}salud del sitio{{/link}} y corrige cualquier problema.','Debug Information'=>'Información de depuración','Show debug'=>'Mostrar depuración','View Data'=>'Ver datos','Redirection stores no user identifiable information other than what is configured above. It is your responsibility to ensure your site meets any applicable {{link}}privacy requirements{{/link}}.'=>'Redirection no almacerna ninguna información que identifique a los usuarios que no esté configurada arriba. Es tu responsabildiad asegurar que el sitio reune cualquier {{link}}requisito de privacidad{{/link}} aplicable.','Capture HTTP header information with logs (except cookies). It may include user information, and could increase your log size.'=>'Captura la información de la cabecera HTTP con registros (excepto cookies). Puede incluir información de usuarios, y podría aumentar el tamaño de tu registro.','Track redirect hits and date of last access. Contains no user information.'=>'Seguimento de visitas a redirecciones y fecha del último acceso. No contiene ninguna información de usuarios.','Log "external" redirects - those not from Redirection. This can increase your log size and contains no user information.'=>'Registra redirecciones «externas» - las que no son de Redirection. Esto puede aumentar el tamaño de tu registro y no contiene ninguna información de usuarios.','Logging'=>'Registro','(IP logging level)'=>'(Nivel de registro de IPs)','Are you sure you want to delete the selected items?'=>'¿Seguro que deseas borrar los elementos seleccionados?','View Redirect'=>'Ver redirección','RSS'=>'RSS','Group by user agent'=>'Agrupar por agente de usuario','Search domain'=>'Buscar dominio','Redirect By'=>'Redirección mediante','Domain'=>'Dominio','Method'=>'Método','If that did not help then {{strong}}create an issue{{/strong}} or send it in an {{strong}}email{{/strong}}.'=>'Si eso no ayuda entonces {{strong}}crea un informe de problemas{{/strong}} o envíalo en un {{strong}}correo electrónico{{/strong}}.','Please check the {{link}}support site{{/link}} before proceeding further.'=>'Por favor, echa un vistazo al {{link}}sitio de soporte{{/link}} antes de seguir adelante.','Exclude from logs'=>'Excluir de los registros','Request Headers'=>'Cabeceras de la solicitud','Redirect Source'=>'Origen de la redirección','Something went wrong when installing Redirection.'=>'Algo fue mal durante la instalación de Redirection.','There was a problem making a request to your site. This could indicate you provided data that did not match requirements, or that the plugin sent a bad request.'=>'Ha habido un problema al hacer una solicitud a tu sitio. Esto podría indicar que has proporcionado datos que no cumplen con los requisitos o que plugin ha enviado una solicitud errónea.','Your WordPress REST API is returning a 404 page. This is almost certainly an external plugin or server configuration issue.'=>'Tu API REST de WordPress está devolviendo una página 404. Es casi seguro que es un problema de un plugin externo o de la configuración del servidor.','You should update your site URL to match your canonical settings: {{code}}%(current)s{{/code}} ⇒ {{code}}%(site)s{{/code}}'=>'Deberías actualizar la URL de tu sitio para que coincida con tus ajustes de la canónica: {{code}}%(current)s{{/code}} &rArr; {{code}}%(site)s{{/code}}','Add Header'=>'Añadir cabecera','Add Security Presets'=>'Añadir preajustes de seguridad','Add CORS Presets'=>'Añadir preajustes CORS','Relocate Site'=>'Reubicar el sitio','Want to redirect the entire site? Enter a domain to redirect everything, except WordPress login and admin. Enabling this option will disable any site aliases or canonical settings.'=>'¿Quieres redirigir todo el sitio? Introduce un dominio para redirigir todo, excepto el acceso a WordPress y la administración. Al activar esta opción se desactivará cualquier alias de sitio o ajustes canónicos.','Relocate to domain'=>'Reubicar a dominio','Need to search and replace?'=>'¿Necesitas buscar y reemplazar?','The companion plugin Search Regex allows you to search and replace data on your site. It also supports Redirection, and is handy if you want to bulk update a lot of redirects.'=>'El plugin de acompañamiento Search Regex te permite buscar y reemplazar datos en tu sitio. También es compatible con Redirection, y es útil si quieres actualizar por lotes montones de redirecciones.','Force a redirect from HTTP to HTTPS - {{code}}%(site)s{{/code}} ⇒ {{code}}%(siteHTTPS)s{{/code}}'=>'Forzar una redirección de HTTP a HTTPS - {{code}}%(site)s{{/code}} &rArr; {{code}}%(siteHTTPS)s{{/code}}','{{strong}}Warning{{/strong}}: ensure your HTTPS is working before forcing a redirect.'=>'{{strong}}Advertencia{{/strong}}: asegúrate de que tu HTTPS está funcionando antes de forzar una redirección.','Preferred domain'=>'Dominio preferido','If you want to redirect everything please use a site relocation or alias from the Site page.'=>'Si deseas redirigir todo, por favor, utiliza una reubicación del sitio o un alias desde la página del sitio.','Options on this page can cause problems if used incorrectly. You can {{link}}temporarily disable them{{/link}} to make changes.'=>'Las opciones en esta página pueden causar problemas si se usan incorrectamente. Puedes {{link}}desactivarlas temporalmente{{/link}} para realizar cambios.','Site Aliases'=>'Alias ​​del sitio','A site alias is another domain that you want to be redirected to this site. For example, an old domain, or a subdomain. This will redirect all URLs, including WordPress login and admin.'=>'Un alias de sitio es otro dominio que deseas redirigir a este sitio. Por ejemplo, un dominio antiguo o un subdominio. Esto redirigirá todas las URL, incluidas las de acceso y administración de WordPress.','You will need to configure your system (DNS and server) to pass requests for these domains to this WordPress install.'=>'Necesitarás configurar tu sistema (DNS y servidor) para pasar solicitudes de estos dominios a esta instalación de WordPress.','Aliased Domain'=>'Dominio con alias','Alias'=>'Alias','No aliases'=>'Sin alias','Add Alias'=>'Añadir alias','Don\'t set a preferred domain - {{code}}%(site)s{{/code}}'=>'No establecer un dominio preferido - {{code}}%(site)s{{/code}}','Remove www from domain - {{code}}%(siteWWW)s{{/code}} ⇒ {{code}}%(site)s{{/code}}'=>'Eliminar www del dominio - {{code}}%(siteWWW)s{{/code}} &rArr; {{code}}%(site)s{{/code}}','Add www to domain - {{code}}%(site)s{{/code}} ⇒ {{code}}%(siteWWW)s{{/code}}'=>'Añadir www al dominio - {{code}}%(site)s{{/code}} &rArr; {{code}}%(siteWWW)s{{/code}}','Canonical Settings'=>'Ajustes canónicos','That\'s all there is to it - you are now redirecting! Note that the above is just an example.'=>'¡Eso es todo - ahora estás redirigiendo! Ten en cuenta que lo de arriba es solo un ejemplo.','Import Existing Redirects'=>'Importar redirecciones existentes','Importing existing redirects from WordPress or other plugins is a good way to get started with Redirection. Check each set of redirects you wish to import.'=>'Importar las redirecciones existentes desde WordPress u otros plugins es un buen modo de empezar con Redirection. Revisa cada conjunto de redirecciones que desees importar.','WordPress automatically creates redirects when you change a post URL. Importing these into Redirection will allow you to manage and monitor them.'=>'WordPress crea automáticamente redirecciones cuando cambias la URL de una entrada. Importarlas en Redirection te permitirá gestionarlas y supervisarlas.','The following plugins have been detected.'=>'Se han detectado los siguientes plugins.','Continue'=>'Seguir','Please wait, importing.'=>'Por favor, espera, importando.','Unable to make request due to browser security. This is typically because your WordPress and Site URL settings are inconsistent, or the request was blocked by your site CORS policy.'=>'No se puede realizar la solicitud debido a la seguridad del navegador. Esto suele ocurrir porque los ajustes de WordPress y de la URL del sitio son inconsistentes o la política de intercambio de recursos de origen cruzado («CORS») de tu sitio ha bloqueado la solicitud.','Site'=>'Sitio','Some servers may be configured to serve file resources directly, preventing a redirect occurring.'=>'Algunos servidores pueden configurarse para servir recursos de archivos directamente, evitando que se produzca una redirección.','Redirect'=>'Redirigir','General'=>'General','Custom Header'=>'Cabecera personalizada','HTTP Headers'=>'Cabeceras HTTP','Site headers are added across your site, including redirects. Redirect headers are only added to redirects.'=>'Las cabeceras del sitio se añaden a todo el sitio, incluyendo las redirecciones. Las cabeceras de redirección solo se añaden a las redirecciones.','Location'=>'Ubicación','Header'=>'Cabecera','No headers'=>'Sin cabeceras','Note that some HTTP headers are set by your server and cannot be changed.'=>'Ten en cuenta que tu servidor establece algunas cabeceras HTTP que no se pueden cambiar.','All'=>'Todo','Values'=>'Valores','Value'=>'Valor','Reload the page - your current session is old.'=>'Recarga la página - tu sesión actual es antigua.','Log out, clear your browser cache, and log in again - your browser has cached an old session.'=>'Sal, vacía la caché de tu navegador y vuelve a acceder - tu navegador ha guardado en la caché una sesión antigua.','URL and language'=>'URL e idioma','451 - Unavailable For Legal Reasons'=>'451 - No disponible por motivos legales','500 - Internal Server Error'=>'500 - Error interno del servidor','501 - Not implemented'=>'501 - No implementado','502 - Bad Gateway'=>'502 - Puerta de enlace incorrecta','503 - Service Unavailable'=>'503 - Servicio no disponible','504 - Gateway Timeout'=>'504 - Tiempo de espera de la puerta de enlace agotado','Language'=>'Idioma','Comma separated list of languages to match against (i.e. da, en-GB)'=>'Lista de idiomas, separados por comas, con los que coincidir (por ejemplo, es_ES)','Your URL appears to contain a domain inside the path: {{code}}%(relative)s{{/code}}. Did you mean to use {{code}}%(absolute)s{{/code}} instead?'=>'Tu URL parece que continene un dominio dentro de la ruta: {{code}}%(relative)s{{/code}}. ¿Querías usar {{code}}%(absolute)s{{/code}} en su lugar?','Display All'=>'Mostrar todo','Custom Display'=>'Vista personalizada','Pre-defined'=>'Predefinido','Status'=>'Estado','Standard Display'=>'Vista estándar','Compact Display'=>'Vista compacta','Enabled'=>'Activada','Disabled'=>'Desactivada','Search URL'=>'Buscar URL','Search referrer'=>'Buscar remitente','Search user agent'=>'Buscar agente de usuario','Search IP'=>'Buscar IP','Search target URL'=>'Buscar URL de destino','Match Type'=>'Tipo de coincidencia','Action Type'=>'Tipo de acción','Code'=>'Código','Source'=>'Fuente','URL match'=>'Coincidencia de URL','Plain'=>'Plano','HTTP Status Code'=>'Código HTTP de estado','Last Accessed'=>'Último acceso','Never accessed'=>'No se ha accedido nunca','Not accessed in last month'=>'No se ha accedido en el último mes','Not accessed in last year'=>'No se ha accedido en el último año','Search title'=>'Buscar título','Exact Query'=>'Consulta exacta','Ignore Query'=>'Ignorar la consulta','Ignore & Pass Query'=>'Ignorar y pasar la consulta','Filter on: %(type)s'=>'Filtrar en: %(type)s','Redirects added to an Apache group can be saved to an {{code}}.htaccess{{/code}} file by adding the full path here. For reference, your WordPress is installed to {{code}}%(installed)s{{/code}}.'=>'La redirecciones añadidas a un grupo de Apache se puede guardar a un fichero {{code}}.htaccess{{/code}} añadiendo aquí la ruta completa. Para tu referencia, tu instalación de WordPress está en {{code}}%(installed)s{{/code}}.','Unable to save .htaccess file'=>'No ha sido posible guardar el archivo .htaccess','Insufficient database permissions detected. Please give your database user appropriate permissions.'=>'Permisos insuficientes para la base de datos detectados. Proporciónale a tu usuario de base de datos los permisos necesarios.','Manual Install'=>'Instalación manual','If your site needs special database permissions, or you would rather do it yourself, you can manually run the following SQL.'=>'Tu sitio necesita permisos especiales para la base de datos. También lo puedes hacer tú mismo ejecutando el siguiente SQL.','Click "Finished! 🎉" when finished.'=>'Haz clic en «¡Terminado! 🎉» cuando hayas acabado.','If you do not complete the manual install you will be returned here.'=>'Si no completas la instalación manual volverás aquí.','If you are using WordPress 5.2 or newer then look at your {{link}}Site Health{{/link}} and resolve any issues.'=>'Si estás usando WordPress 5.2 o superior, mira en tu {{link}}salud del sitio{{/link}} y resuelve los problemas.','Your target URL contains the invalid character {{code}}%(invalid)s{{/code}}'=>'Tu dirección de destino contiene el carácter no válido {{code}}%(invalid)s{{/code}}','You will need at least one working REST API to continue.'=>'Necesitarás al menos una API REST funcionando para continuar.','I need support!'=>'¡Necesito ayuda!','Note that you will need to set the Apache module path in your Redirection options.'=>'Ten en cuenta que necesitarás establecer la ruta del módulo de Apache en tus opciones de Redirection.','All imports will be appended to the current database - nothing is merged.'=>'Todas las importaciones se adjuntarán a la base de datos actual; nada se combina.','CSV does not include all information, and everything is imported/exported as "URL only" matches. Use the JSON format for a full set of data.'=>'El CSV no incluye toda la información, y todo se importa/exporta como coincidencias de «Sólo URL». Usa el formato JSON para obtener un conjunto completo de datos.','Export to CSV, Apache .htaccess, Nginx, or Redirection JSON. The JSON format contains full information, and other formats contain partial information appropriate to the format.'=>'Exporta a CSV, .htaccess de Apache, Nginx o JSON de Redirection. El formato JSON contiene información completa, y otros formatos contienen información parcial apropiada para el formato.','Complete data (JSON)'=>'Datos completos (JSON)','Database version'=>'Versión de base de datos','Do not change unless advised to do so!'=>'¡No lo cambies a menos que te lo indiquen!','IP Headers'=>'Cabeceras IP','Redirection communicates with WordPress through the WordPress REST API. This is a standard part of WordPress, and you will experience problems if you cannot use it.'=>'Redirection se comunica con WordPress a través de la REST API de WordPress. Este es un componente estándar de WordPress, y tendrás problemas si no puedes usarla.','Plugin Debug'=>'Depuración del plugin','This information is provided for debugging purposes. Be careful making any changes.'=>'Esta información se proporciona con propósitos de depuración. Ten cuidado al hacer cambios.','Show Problems'=>'Mostrar problemas','Testing - %s$'=>'Comprobando - %s$','Check Again'=>'Comprobar otra vez','Read this REST API guide for more information.'=>'Lee esta guía de la REST API para más información.','Your REST API is probably being blocked by a security plugin. Please disable this, or configure it to allow REST API requests.'=>'Es probable que tu REST API esté siendo bloqueada por un plugin de seguridad. Por favor, desactívalo o configúralo para permitir solicitudes de la REST API.','This could be a security plugin, or your server is out of memory or has an external error. Please check your server error log'=>'Esto podría ser un plugin de seguridad, o que tu servidor está sin memoria o que exista un error externo. Por favor, comprueba el registro de errores de tu servidor','Possible cause'=>'Posible causa','What do I do next?'=>'¿Qué hago a continuación?','Create An Issue'=>'Crear una incidencia','Include these details in your report along with a description of what you were doing and a screenshot.'=>'Incluye estos detalles en tu informe junto con una descripción de lo que estabas haciendo y una captura de pantalla.','The target URL you want to redirect, or auto-complete on post name or permalink.'=>'La URL de destino que quieres redirigir o autocompletar automáticamente en el nombre de la publicación o enlace permanente.','Your source is the same as a target and this will create a loop. Leave a target blank if you do not want to take action.'=>'Tu fuente es la misma que la de destino, y esto creará un bucle. Deja el destino en blanco si no quieres tomar medidas.','Your target URL should be an absolute URL like {{code}}https://domain.com/%(url)s{{/code}} or start with a slash {{code}}/%(url)s{{/code}}.'=>'Tu URL de destino debería ser una URL absoluta como {{code}}https://domain.com/%(url)s{{/code}} o comenzar con una barra inclinada {{code}}/%(url)s{{/code}}.','Working!'=>'¡Trabajando!','Show Full'=>'Mostrar completo','Hide'=>'Ocultar','Working but some issues'=>'Funciona pero con algunos problemas','Unavailable'=>'No disponible','There are some problems connecting to your REST API. It is not necessary to fix these problems and the plugin is able to work.'=>'Hay algunos problemas para conectarse a tu REST API. No es necesario solucionar estos problemas y el plugin puede funcionar.','Your REST API is not working and the plugin will not be able to continue until this is fixed.'=>'Tu REST API no funciona y el plugin no podrá continuar hasta que esto se arregle.','Summary'=>'Resumen','URL options / Regex'=>'Opciones de URL / Regex','Export redirect'=>'Exportar redirecciones','Export 404'=>'Exportar 404','Ignore Slash'=>'Ignorar barra inclinada','Ignore Case'=>'Ignorar mayúsculas/minúsculas','Ignore all parameters'=>'Ignorar todos los parámetros','Ignore & pass parameters to the target'=>'Ignorar y pasar parámetros al destino','Query Parameters'=>'Parámetros de consulta','URL options'=>'Opciones de URL','A security plugin (e.g Wordfence)'=>'Un plugin de seguridad (p. ej. Wordfence)','Caching software (e.g Cloudflare)'=>'Software de caché (p. ej. Cloudflare)','Exact match'=>'Coincidencia exacta','Ignore all query parameters'=>'Ignora todos los parámetros de consulta','Ignore and pass all query parameters'=>'Ignora y pasa todos los parámetros de consulta','Default URL settings'=>'Ajustes de URL por defecto','Applies to all redirections unless you configure them otherwise.'=>'Se aplica a todas las redirecciones a menos que las configures de otro modo.','Case insensitive matches (i.e. {{code}}/Exciting-Post{{/code}} will match {{code}}/exciting-post{{/code}})'=>'Sin coincidencia de mayúsculas/minúsculas (p.ej. {{code}}/Entrada-Alucinante{{/code}} coincidirá con {{code}}/entrada-alucinante{{/code}})','Ignore trailing slashes (i.e. {{code}}/exciting-post/{{/code}} will match {{code}}/exciting-post{{/code}})'=>'Ignora barras invertidas (p.ej. {{code}}/entrada-alucinante/{{/code}} coincidirá con {{code}}/entrada-alucinante{{/code}})','Default query matching'=>'Coincidencia de consulta por defecto','Exact - matches the query parameters exactly defined in your source, in any order'=>'Coincidencia exacta - coincide exactamente con los parámetros de consulta definidos en tu origen, en cualquier orden','Ignore - as exact, but ignores any query parameters not in your source'=>'Ignorar - como la coincidencia exacta, pero ignora cualquier parámetro de consulta que no esté en tu origen','Pass - as ignore, but also copies the query parameters to the target'=>'Pasar - como ignorar, pero también copia los parámetros de consulta al destino','Disabled! Detected PHP %1$s, need PHP %2$s+'=>'¡Desactivado! Detectado PHP %1$s, se necesita PHP %2$s o superior','(Example) The source URL is your old or original URL'=>'(Ejemplo) La URL de origen es tu URL antigua u original','(Example) The target URL is the new URL'=>'(Ejemplo) La URL de destino es la nueva URL','Default REST API'=>'API REST por defecto','Raw REST API'=>'API REST completa','Relative REST API'=>'API REST relativa','Redirection\'s database needs to be updated - <a href="%1$1s">click to update</a>.'=>'Hay que actualizar la base de datos de Redirection - <a href="%1$1s">haz clic para actualizar</a>.','Remember to enable the "regex" option if this is a regular expression.'=>'Recuerda activar la opción «regex» si se trata de una expresión regular.','To prevent a greedy regular expression you can use {{code}}^{{/code}} to anchor it to the start of the URL. For example: {{code}}%(example)s{{/code}}'=>'Para evitar una expresión regular ambiciosa, puedes utilizar un {{code}}^{{/code}} para anclarla al inicio de la URL. Por ejemplo: {{code}}%(ejemplo)s{{/code}}.','Welcome to Redirection 🚀🎉'=>'Bienvenido a Redirection 🚀🎉','Thank you for installing and using Redirection v%(version)s. This plugin will allow you to manage 301 redirections, keep track of 404 errors, and improve your site, with no knowledge of Apache or Nginx needed.'=>'Gracias por instalar y usar Redirection v%(version)s. Este plugin te permitirá gestionar redirecciones 301, realizar un seguimiento de los errores 404, y mejorar tu sitio, sin necesidad de tener conocimientos de Apache o Nginx.','Redirection is designed to be used on sites with a few redirects to sites with thousands of redirects.'=>'Redirection está diseñado para utilizarse desde sitios con unos pocos redirecciones a sitios con miles de redirecciones.','How do I use this plugin?'=>'¿Cómo utilizo este plugin?','A simple redirect involves setting a {{strong}}source URL{{/strong}} (the old URL) and a {{strong}}target URL{{/strong}} (the new URL). Here\'s an example:'=>'Una redirección simple implica configurar una {{strong}}URL de origen{{/strong}}} (la URL antigua) y una {{strong}}URL de destino{{/strong}} (la nueva URL). Aquí tienes un ejemplo:','Full documentation can be found on the {{link}}Redirection website.{{/link}}'=>'La documentación completa la puedes encontrar en la {{link}}web de Redirection{{/link}}.','Some features you may find useful are'=>'Algunas de las características que puedes encontrar útiles son','{{link}}Import{{/link}} from .htaccess, CSV, and a variety of other plugins'=>'{{link}}Importar{{/link}} desde .htaccess, CSV, y una gran variedad de otros plugins','More powerful URL matching, including {{regular}}regular expressions{{/regular}}, and {{other}}other conditions{{/other}}'=>'Coincidencia de URLs más potente, incluidas las expresiones {{regular}}regulares {{/regular}}, y {{other}} otras condiciones{{{/other}}.','Check a URL is being redirected'=>'Comprueba si una URL está siendo redirigida','What\'s next?'=>'¿Cuáles son las novedades?','First you will be asked a few questions, and then Redirection will set up your database.'=>'Primero se te harán algunas preguntas, y luego Redirection configurará tu base de datos.','Start Setup'=>'Iniciar configuración','Basic Setup'=>'Configuración básica','These are some options you may want to enable now. They can be changed at any time.'=>'Estas son algunas de las opciones que puedes activar ahora. Se pueden cambiar en cualquier momento.','Monitor permalink changes in WordPress posts and pages'=>'Supervisar los cambios de los enlaces permanentes en las entradas y páginas de WordPress','If you change the permalink in a post or page then Redirection can automatically create a redirect for you.'=>'Si cambias el enlace permanente en una entrada o página, entonces Redirection puede crear automáticamente una redirección para ti.','{{link}}Read more about this.{{/link}}'=>'{{link}}Leer más sobre esto.{{/link}}','Keep a log of all redirects and 404 errors.'=>'Guardar un registro de todas las redirecciones y errores 404.','Storing logs for redirects and 404s will allow you to see what is happening on your site. This will increase your database storage requirements.'=>'Almacena registros de redirecciones y 404s te permitirá ver lo que está pasando en tu sitio. Esto aumentará los requisitos de almacenamiento de la base de datos.','Store IP information for redirects and 404 errors.'=>'Almacenar información de IPs de las redirecciones y errores 404.','Storing the IP address allows you to perform additional log actions. Note that you will need to adhere to local laws regarding the collection of data (for example GDPR).'=>'El almacenamiento de la dirección IP te permite realizar acciones de registro adicionales. Ten en cuenta que tendrás que cumplir con las leyes locales relativas a la recopilación de datos (por ejemplo, RGPD).','Go back'=>'Volver','Redirection uses the {{link}}WordPress REST API{{/link}} to communicate with WordPress. This is enabled and working by default. Sometimes the REST API is blocked by:'=>'Redirection utiliza la {{link}}WordPress REST API{{/link}} para comunicarse con WordPress. Esto está activado y funciona de forma predeterminada. A veces la API REST está bloqueada por:','A server firewall or other server configuration (e.g OVH)'=>'Un cortafuegos del servidor u otra configuración del servidor (p.ej. OVH)','Some other plugin that blocks the REST API'=>'Algún otro plugin que bloquea la API REST','If you do experience a problem then please consult your plugin documentation, or try contacting your host support. This is generally {{link}}not a problem caused by Redirection{{/link}}.'=>'Si tienes algún problema, por favor consulta la documentación de tu plugin, o intenta contactar con el soporte de tu alojamiento. Esto es normalmente {{{link}}no suele ser un problema causado por Redirection{{/link}}.','You have different URLs configured on your WordPress Settings > General page, which is usually an indication of a misconfiguration, and it can cause problems with the REST API. Please review your settings.'=>'Tienes diferentes URLs configuradas en tu página ajustes de WordPress > General, lo que normalmente es una indicación de una mala configuración, y puede causar problemas con la API REST. Por favor, revisa tus ajustes.','Finish Setup'=>'Finalizar configuración','Install Redirection tables'=>'Instalar tablas de Redirection','Create basic data'=>'Crear datos básicos','Table "%s" is missing'=>'La tabla "%s" no existe','Your database does not need updating to %s.'=>'Tu base de datos no necesita actualizarse a %s.','Please complete your <a href="%s">Redirection setup</a> to activate the plugin.'=>'Por favor, completa tu <a href="%s">configuración de Redirection</a> para activar el plugin.','Upgrade Database'=>'Actualizar base de datos','Please upgrade your database'=>'Por favor, actualiza tu base de datos','Please enable JavaScript'=>'Por favor, activa JavaScript','Database problem'=>'Problema en la base de datos','Try again'=>'Intentarlo de nuevo','Skip this stage'=>'Saltarse esta etapa','Stop upgrade'=>'Parar actualización','If you want to {{support}}ask for support{{/support}} please include these details:'=>'Si quieres {{support}}solicitar ayuda{{/support}}por favor, incluye estos detalles:','Please remain on this page until complete.'=>'Por favor, permanece en esta página hasta que se complete.','Upgrading Redirection'=>'Actualizando Redirection','Setting up Redirection'=>'Configurando Redirection','Leaving before the process has completed may cause problems.'=>'Salir antes de que el proceso haya terminado puede causar problemas.','Progress: %(complete)d$'=>'Progreso: %(complete)d$','Finished! 🎉'=>'¡Terminado! 🎉','Anchor values are not sent to the server and cannot be redirected.'=>'Los valores de anclaje no se envían al servidor y no pueden ser redirigidos.','This will be converted to a server redirect for the domain {{code}}%(server)s{{/code}}.'=>'Esto se convertirá en una redirección de servidor para el dominio {{code}}%(server)s{{{/code}}}.','The source URL should probably start with a {{code}}/{{/code}}'=>'La URL de origen probablemente debería comenzar con un {{code}}/{{/code}}.','{{link}}Monitor 404 errors{{/link}}, get detailed information about the visitor, and fix any problems'=>'{{link}}Supervisar errores 404{{/link}}, obtiene información detallada sobre el visitante y corrige cualquier problema','Site and home URL are inconsistent. Please correct from your Settings > General page: %1$1s is not %2$2s'=>'La URL del sitio y de inicio no son consistentes. Por favor, corrígelo en tu página de Ajustes > Generales: %1$1s no es igual a %2$2s','Count'=>'Contador','Redirect All'=>'Redirigir todo','Block IP'=>'Bloquear IP','Ignore URL'=>'Ignorar URL','No grouping'=>'Sin agrupar','Group by URL'=>'Agrupar por URL','Group by IP'=>'Agrupar por IP','Delete Log Entries'=>'Borrar entradas del registro','Delete logs for this entry'=>'Borrar los registros de esta entrada','Delete logs for these entries'=>'Borrar los registros de estas entradas','Show All'=>'Mostrar todo','Target URL when matched (empty to ignore)'=>'URL de destino cuando coinciden (vacío para ignorar)','Target URL when not matched (empty to ignore)'=>'URL de destino cuando no coinciden (vacío para ignorar)','Do nothing (ignore)'=>'No hacer nada (ignorar)','303 - See Other'=>'303 - Ver otra','304 - Not Modified'=>'304 - No modificada','400 - Bad Request'=>'400 - Mala petición','403 - Forbidden'=>'403 - Prohibido','418 - I\'m a teapot'=>'418 - Soy una tetera','Describe the purpose of this redirect (optional)'=>'Describe la finalidad de esta redirección (opcional)','Enter IP addresses (one per line)'=>'Introduce direcciones IP (una por línea)','Page Type'=>'Tipo de página','Only the 404 page type is currently supported.'=>'De momento solo es compatible con el tipo 404 de página de error.','Please do not try and redirect all your 404s - this is not a good thing to do.'=>'Por favor, no intentes redirigir todos tus 404s - no es una buena idea.','URL and IP'=>'URL e IP','URL and WordPress page type'=>'URL y tipo de página de WordPress','Error'=>'Error','Check redirect for: {{code}}%s{{/code}}'=>'Comprobar la redirección para: {{code}}%s{{/code}}','Check Redirect'=>'Comprobar la redirección','Check'=>'Comprobar','Good'=>'Bueno','Problem'=>'Problema','Enter full URL, including http:// or https://'=>'Introduce la URL completa, incluyendo http:// o https://','Add New'=>'Añadir nueva','The relative URL you want to redirect from'=>'La URL relativa desde la que quieres redirigir','Match against this browser user agent'=>'Comparar contra el agente usuario de este navegador','Match against this browser referrer text'=>'Comparar contra el texto de referencia de este navegador','Role'=>'Perfil','Enter role or capability value'=>'Escribe el valor de perfil o capacidad','Server'=>'Servidor','Enter server URL to match against'=>'Escribe la URL del servidor que comprobar','Target'=>'Destino','Redirect Tester'=>'Probar redirecciones','URL and server'=>'URL y servidor','URL and role/capability'=>'URL y perfil/capacidad','Site and home are consistent'=>'Portada y sitio son consistentes','Site and home protocol'=>'Protocolo de portada y el sitio','URL and cookie'=>'URL y cookie','URL and custom filter'=>'URL y filtro personalizado','URL and HTTP header'=>'URL y cabecera HTTP','If you are using a caching system such as Cloudflare then please read this: '=>'Si estás usando un sistema de caché como Cloudflare entonces, por favor, lee esto:','clearing your cache.'=>'vaciando tu caché.','Cookie'=>'Cookie','Cookie name'=>'Nombre de la cookie','Cookie value'=>'Valor de la cookie','Filter Name'=>'Nombre del filtro','WordPress filter name'=>'Nombre del filtro WordPress','HTTP Header'=>'Cabecera HTTP','Header name'=>'Nombre de cabecera','Header value'=>'Valor de cabecera','Accept Language'=>'Aceptar idioma','Note it is your responsibility to pass HTTP headers to PHP. Please contact your hosting provider for support about this.'=>'Date cuenta de que es tu responsabilidad pasar las cabeceras HTTP a PHP. Por favor, contacta con tu proveedor de alojamiento para obtener soporte sobre esto.','WordPress REST API'=>'REST API de WordPress','Unable to load Redirection ☹️'=>'No se puede cargar Redirection ☹️','Please see the <a href="https://redirection.me/support/problems/">list of common problems</a>.'=>'Por favor, consulta la <a href="https://redirection.me/support/problems/">lista de problemas habituales</a>.','{{link}}Please temporarily disable other plugins!{{/link}} This fixes so many problems.'=>'{{link}}Por favor, ¡desactiva temporalmente otros plugins!{{/link}} Esto arregla muchos problemas.','{{link}}Caching software{{/link}}, in particular Cloudflare, can cache the wrong thing. Try clearing all your caches.'=>'{{link}}Un software de caché{{/link}}, en particular Cloudflare, podría cachear lo que no debería. Prueba a borrar todas tus cachés.','Take a look at the {{link}}plugin status{{/link}}. It may be able to identify and "magic fix" the problem.'=>'Por favor, echa un vistazo al {{link}}estado del plugin{{/link}}. Podría ser capaz de identificar y resolver "mágicamente" el problema.','How Redirection uses the REST API - don\'t change unless necessary'=>'Cómo utiliza Redirection la REST API - no cambiar a no ser que sea necesario','REST API'=>'API REST','404 deleted'=>'404 borrado','You can find full documentation about using Redirection on the <a href="%s" target="_blank">redirection.me</a> support site.'=>'Puedes encontrar la documentación completa sobre el uso de Redirection en el sitio de soporte <a href="%s" target="_blank">redirection.me</a>.','Please note that Redirection requires the WordPress REST API to be enabled. If you have disabled this then you won\'t be able to use Redirection'=>'Ten en cuenta que Redirection requiere que la API REST de WordPress esté activada. Si la has desactivado, no podrás usar Redirection','Trash'=>'Papelera','Powered by {{link}}redirect.li{{/link}}'=>'Funciona gracias a {{link}}redirect.li{{/link}}','Geo Location'=>'Geolocalización','Timezone'=>'Zona horaria','Area'=>'Área','City'=>'Ciudad','Geo IP'=>'Geolocalización de IP','No details are known for this address.'=>'No se conoce ningún detalle para esta dirección.','This is an IP from a private network. This means it is located inside a home or business network and no more information can be displayed.'=>'Esta es una IP de una red privada. Significa que se encuentra dentro de una casa o red de empresa y no se puede mostrar más información.','Something went wrong obtaining this information'=>'Algo ha ido mal obteniendo esta información','Geo IP Error'=>'Error de geolocalización de IP','Filter by IP'=>'Filtrar por IP','Agent Info'=>'Información de agente','Geo Info'=>'Información de geolocalización','IP Logging'=>'Registro de IP','Monitor changes to %(type)s'=>'Supervisar cambios de %(type)s','Anonymize IP (mask last part)'=>'Anonimizar IP (enmascarar la última parte)','Full IP logging'=>'Registro completo de IP','No IP logging'=>'Sin registro de IP','Agent'=>'Agente','Useragent'=>'Agente de usuario','Engine'=>'Motor','Browser'=>'Navegador','Operating System'=>'Sistema operativo','Device'=>'Dispositivo','Unknown Useragent'=>'Agente de usuario desconocido','Useragent Error'=>'Error de agente de usuario','If you want to report a bug please read the {{report}}Reporting Bugs{{/report}} guide.'=>'Si quieres informar de un fallo, por favor lee la guía {{report}}Informando de fallos{{/report}}','Full documentation for Redirection can be found at {{site}}https://redirection.me{{/site}}. If you have a problem please check the {{faq}}FAQ{{/faq}} first.'=>'La documentación completa de Redirection está en {{site}}https://redirection.me{{/site}}. Si tienes algún problema, por favor revisa primero las {{faq}}FAQ{{/faq}}.','https://redirection.me/'=>'https://redirection.me/','If you want to submit information that you don\'t want in a public repository then send it directly via {{email}}email{{/email}} - include as much information as you can!'=>'Si quieres enviar información y no quieres que se incluya en un repositorio público, envíala directamente por {{email}}correo electrónico{{/email}} - ¡incluye toda la información que puedas!','Default WordPress "old slugs"'=>'"Viejos slugs" por defecto de WordPress','Redirection requires WordPress v%1$1s, you are using v%2$2s - please update your WordPress'=>'Redirection requiere WordPress v%1$1s, estás  usando v%2$2s - por favor, actualiza tu WordPress','Import from %s'=>'Importar de %s','total = '=>'total = ','The following redirect plugins were detected on your site and can be imported from.'=>'Se han detectado los siguientes plugins de redirección en tu sitio y se puede importar desde ellos.','Plugin Importers'=>'Importadores de plugins','Are you sure you want to import from %s?'=>'¿Estás seguro de querer importar de %s?','How long to cache redirected 301 URLs (via "Expires" HTTP header)'=>'Cuánto tiempo cachear URLs con redirección 301 (mediante la cabecera HTTP "Expires")','An hour'=>'Una hora','Never cache'=>'No cachear nunca','Redirect Caching'=>'Redireccionar caché','<code>Redirectioni10n</code> is not defined. This usually means another plugin is blocking Redirection from loading. Please disable all plugins and try again.'=>'<code>Redirectioni10n</code> no está definido. Esto normalmente significa que otro plugin está impidiendo que cargue Redirection. Por favor, desactiva todos los plugins e inténtalo de nuevo.','Create associated redirect (added to end of URL)'=>'Crea una redirección asociada (añadida al final de la URL)','Unable to load Redirection'=>'No ha sido posible cargar Redirection','Also check if your browser is able to load <code>redirection.js</code>:'=>'También comprueba si tu navegador puede cargar <code>redirection.js</code>:','Database tables'=>'Tablas de la base de datos','Valid groups'=>'Grupos válidos','No valid groups, so you will not be able to create any redirects'=>'No hay grupos válidos, así que no podrás crear redirecciones','Valid groups detected'=>'Detectados grupos válidos','Valid redirect group'=>'Grupo de redirección válido','Redirects with invalid groups detected'=>'Detectadas redirecciones con grupos no válidos','All redirects have a valid group'=>'Todas las redirecciones tienen un grupo válido','Post monitor group'=>'Grupo de supervisión de entradas','Post monitor group is invalid'=>'El grupo de supervisión de entradas no es válido','Post monitor group is valid'=>'El grupo de supervisión de entradas es válido','If you are using a page caching plugin or service (CloudFlare, OVH, etc) then you can also try clearing that cache.'=>'Si estás  usando un plugin o servicio (CloudFlare, OVH, etc.) de caché de página entonces también puedes probar a vaciar la caché.','Your server has rejected the request for being too big. You will need to reconfigure it to continue.'=>'Tu servidor rechazó la petición por ser demasiado grande. Necesitarás volver a configurarla para continuar.','URL Monitor'=>'Supervisar URL','For example "/amp"'=>'Por ejemplo "/amp"','Save changes to this group'=>'Guardar los cambios de este grupo','URL Monitor Changes'=>'Supervisar cambios de URL','Libraries'=>'Bibliotecas','Feed Readers'=>'Lectores de feeds','Mobile'=>'Móvil','Custom'=>'Personalizado','Plugin Status'=>'Estado del plugin','⚡️ Magic fix ⚡️'=>'⚡️ Arreglo mágico ⚡️','If the magic button doesn\'t work then you should read the error and see if you can fix it manually, otherwise follow the \'Need help\' section below.'=>'Si no funciona el botón mágico entonces deberías leer el error y ver si puedes arreglarlo manualmente, o sino seguir la sección \'Necesito ayuda\' de abajo.','All tables present'=>'Están presentes todas las tablas','The following tables are missing:'=>'Faltan las siguientes tablas:','Loading, please wait...'=>'Cargando, por favor espera…','This may be caused by another plugin - look at your browser\'s error console for more details.'=>'Esto podría estar provocado por otro plugin - revisa la consola de errores de tu navegador para más detalles.','If you think Redirection is at fault then create an issue.'=>'Si crees que es un fallo de Redirection entonces envía un aviso de problema.','WordPress did not return a response. This could mean an error occurred or that the request was blocked. Please check your server error_log.'=>'WordPress no ha devuelto una respuesta. Esto podría significar que ocurrió un error o que la petición se bloqueó. Por favor, revisa el error_log de tu servidor.','Please clear your browser cache and reload this page.'=>'Por favor, vacía la caché de tu navegador y recarga esta página','Cached Redirection detected'=>'Detectada caché de Redirection','Email'=>'Correo electrónico','Create Issue'=>'Crear aviso de problema','If that doesn\'t help, open your browser\'s error console and create a {{link}}new issue{{/link}} with the details.'=>'Si eso no ayuda abre la consola de errores de tu navegador y crea un {{link}}aviso de problema nuevo{{/link}} con los detalles.','Redirection is not working. Try clearing your browser cache and reloading this page.'=>'La redirección no está funcionando. Trata de vaciar la caché de tu navegador y recarga esta página.','{{strong}}CSV file format{{/strong}}: {{code}}source URL, target URL{{/code}} - and can be optionally followed with {{code}}regex, http code{{/code}} ({{code}}regex{{/code}} - 0 for no, 1 for yes).'=>'{{strong}}formato de archivo CSV{{/strong}}: {{code}}URL de origen, URL de destino{{/code}} - y puede añadirse opcionalmente {{code}}regex, http code{{/code}} ({{code}}regex{{/code}} - 0 para no, 1 para sí).','Position'=>'Posición','410 - Gone'=>'410 - Desaparecido','Pos'=>'Pos','Please note that any support is provide on as-time-is-available basis and is not guaranteed. I do not provide paid support.'=>'Por favor, date cuenta de que todo soporte se ofrece sobre la base del tiempo disponible y no está garantizado. No ofrezco soporte de pago.','Need help?'=>'¿Necesitas ayuda?','404 errors'=>'Errores 404','Logs'=>'Registros','Import/Export'=>'Importar/Exportar','View'=>'Ver','Nginx rewrite rules'=>'Reglas de rewrite de Nginx','Apache .htaccess'=>'.htaccess de Apache','CSV'=>'CSV','Nginx redirects'=>'Redirecciones Nginx','Apache redirects'=>'Redirecciones Apache','WordPress redirects'=>'Redirecciones WordPress','Everything'=>'Todo','Export'=>'Exportar','Close'=>'Cerrar','OK'=>'Aceptar','Double-check the file is the correct format!'=>'¡Vuelve a comprobar que el archivo esté en el formato correcto!','Total redirects imported:'=>'Total de redirecciones importadas:','Finished importing'=>'Importación finalizada','Importing'=>'Importando','File selected'=>'Archivo seleccionado','Add File'=>'Añadir archivo','Click \'Add File\' or drag and drop here.'=>'Haz clic en \'Añadir archivo\' o arrastra y suelta aquí.','Import a CSV, .htaccess, or JSON file.'=>'Importa un archivo CSV, .htaccess o JSON.','Import to group'=>'Importar a un grupo','Support 💰'=>'Apoyar 💰','I\'d like to support some more.'=>'Me gustaría dar algo más de apoyo.','Used to auto-generate a URL if no URL is given. Use the special tags {{code}}$dec${{/code}} or {{code}}$hex${{/code}} to insert a unique ID instead'=>'Se usa para generar automáticamente una URL si no se ofrece una URL. Utiliza las etiquetas especiales {{code}}$dec${{/code}} o {{code}}$hex${{/code}} para insertar un ID único insertado','View notice'=>'Ver aviso','Saving...'=>'Guardando…','Unmatched Target'=>'Objetivo no coincidente','Matched Target'=>'Objetivo coincidente','Show advanced options'=>'Mostrar opciones avanzadas','with HTTP code'=>'con el código HTTP','When matched'=>'Cuando coincide','Title'=>'Título','404 - Not Found'=>'404 - No encontrado','401 - Unauthorized'=>'401 - No autorizado','308 - Permanent Redirect'=>'308 - Redirección permanente','307 - Temporary Redirect'=>'307 - Redirección temporal','302 - Found'=>'302 - Encontrado','301 - Moved Permanently'=>'301 - Movido permanentemente','All groups'=>'Todos los grupos','pass'=>'pass','Group saved'=>'Grupo guardado','Settings saved'=>'Ajustes guardados','Log deleted'=>'Registro borrado','Redirection saved'=>'Redirección guardada','Are you sure you want to delete this item?'=>'¿Seguro que quieres borrar este elemento?' . "\0" . '¿Seguro que quieres borrar estos %d elementos?','Log entries (%d max)'=>'Entradas del registro (máximo %d)','Something went wrong 🙁'=>'Algo fue mal 🙁','Sorry, something went wrong loading the data - please try again'=>'Lo siento, pero algo fue mal al cargar los datos - por favor, inténtalo de nuevo','Select All'=>'Elegir todos','%s item'=>'%s elemento' . "\0" . '%s elementos','Last page'=>'Última página','Next page'=>'Página siguiente','of %(page)s'=>'de %(page)s','Current Page'=>'Página actual','Prev page'=>'Página anterior','First page'=>'Primera página','Apply'=>'Aplicar','Bulk Actions'=>'Acciones en lote','No! Don\'t delete the plugin'=>'¡No! No borrar el plugin','Yes! Delete the plugin'=>'¡Sí! Borrar el plugin','Once deleted your redirections will stop working. If they appear to continue working then please clear your browser cache.'=>'Una vez borres tus redirecciones dejarán de funcionar. Si parece que siguen funcionando entonces, por favor, vacía la caché de tu navegador.','Deleting the plugin will remove all your redirections, logs, and settings. Do this if you want to remove the plugin for good, or if you want to reset the plugin.'=>'Al borrar el plugin se eliminarán todas tus redirecciones, registros y ajustes. Haz esto si estás seguro de que quieres borrar el plugin, o si quieres restablecer el plugin. ','Delete the plugin - are you sure?'=>'Borrar el plugin - ¿estás seguro?','Forever'=>'Siempre','You get useful software and I get to carry on making it better.'=>'Tienes un software útil y yo seguiré haciéndolo mejor.','You\'ve supported this plugin - thank you!'=>'Ya has apoyado a este plugin - ¡gracias!','Your email address:'=>'Tu dirección de correo electrónico:','Sign up for the tiny Redirection newsletter - a low volume newsletter about new features and changes to the plugin. Ideal if you want to test beta changes before release.'=>'Regístrate al pequeño boletín de Redirection - un boletín liviano sobre las nuevas funcionalidades y cambios en el plugin. Ideal si quieres probar los cambios de la versión beta antes de su lanzamiento.','Want to keep up to date with changes to Redirection?'=>'¿Quieres estar al día de los cambios en Redirection?','Newsletter'=>'Boletín','Thanks for subscribing! {{a}}Click here{{/a}} if you need to return to your subscription.'=>'¡Gracias por suscribirte! {{a}}Haz clic aquí{{/a}} si necesitas volver a tu suscripción.','WordPress'=>'WordPress','Settings'=>'Ajustes','Redirection'=>'Redirection','Download'=>'Descargar','Cancel'=>'Cancelar','Add new redirection'=>'Añadir nueva redirección','Match'=>'Coincidencia','Regular Expression'=>'Expresión regular','Group'=>'Grupo','Save'=>'Guardar','Groups'=>'Grupos','Search'=>'Buscar','Add Group'=>'Añadir grupo','Use groups to organise your redirects. Groups are assigned to a module, which affects how the redirects in that group work. If you are unsure then stick to the WordPress module.'=>'Utiliza grupos para organizar tus redirecciones. Los grupos se asignan a un módulo, lo cual afecta a cómo se realizan las redirecciones en ese grupo. Si no estás seguro entonces utiliza el módulo WordPress.','No logs'=>'No hay logs','A day'=>'Un dia','A week'=>'Una semana','A month'=>'Un mes','Two months'=>'Dos meses','Options'=>'Opciones','Plugin Support'=>'Apoya el plugin','I\'m a nice person and I have helped support the author of this plugin'=>'Soy una buena persona y he apoyado al autor de este plugin','Redirect Logs'=>'Registros de redirecciones','(time to keep logs for)'=>'(tiempo que se mantendrán los registros)','404 Logs'=>'Registros 404','RSS Token'=>'Token RSS','A unique token allowing feed readers access to Redirection log RSS (leave blank to auto-generate)'=>'Un token único que permite acceso de los lectores de feeds a los registros RSS de Redirection (déjalo en blanco para que se genere automáticamente)','Auto-generate URL'=>'Auto generar URL','Update'=>'Actualizar','Import'=>'Importar','Upload'=>'Subir','Delete Redirection'=>'Borrar Redirection','Selecting this option will delete all redirections, all logs, and any options associated with the Redirection plugin.  Make sure this is what you want to do.'=>'Seleccionando esta opción borrara todas las  redirecciones, todos los registros, y cualquier opción asociada con el plugin Redirection.  Asegurese que es esto lo que desea hacer.','Log'=>'Registro','404s'=>'404s','Support'=>'Soporte','Redirection Support'=>'Soporte de Redirection','Redirection is free to use - life is wonderful and lovely! It has required a great deal of time and effort to develop and you can help support this development by {{strong}}making a small donation{{/strong}}.'=>'Redirection se puede usar gratis - ¡La vida es maravillosa y encantadora! Sin embargo, ha requerido una gran cantidad de tiempo y esfuerzo desarrollarlo y, si te ha sido útil, puedes ayudar a este desarrollo {{strong}}haciendo una pequeña donación{{/strong}}. ','Manage all your 301 redirects and monitor 404 errors'=>'Gestiona todas tus redirecciones 301 y supervisa tus errores 404','John Godley'=>'John Godley','Error (404)'=>'Error (404)','URL and login status'=>'Estado de URL y conexión','Logged In'=>'Conectado','Logged Out'=>'Desconectado','URL and referrer'=>'URL y referente','Referrer'=>'Referente','Regex'=>'Expresión regular','HTTP code'=>'Código HTTP','URL only'=>'Sólo URL','Target URL'=>'URL de destino','URL and user agent'=>'URL y cliente de usuario (user agent)','User Agent'=>'Agente usuario HTTP','Redirections'=>'Redirecciones','Modified Posts'=>'Entradas modificadas','URL'=>'URL','Hits'=>'Hits','Last Access'=>'Último acceso','Edit'=>'Editar','Delete'=>'Borrar','Disable'=>'Desactivar','Enable'=>'Activar','Reset hits'=>'Restablecer aciertos','Filters'=>'Filtros','Name'=>'Nombre','Redirects'=>'Redirecciones','Module'=>'Módulo','View Redirects'=>'Ver redirecciones','Add Redirect'=>'Añadir redirección','Date'=>'Fecha','Source URL'=>'URL de origen','IP'=>'IP','Redirect to URL'=>'Redirigir a URL','Redirect to random post'=>'Redirigir a entrada aleatoria','Pass-through'=>'Pasar directo']];